mapper.select:
SELECT id,
       domain_id AS domainId,
       device_model_id AS deviceModelId
FROM domain_device_model
WHERE domain_id = #{domainId}
  AND device_model_id = #{deviceModelId}

mapper.delete:
DELETE FROM domain_device_model
WHERE domain_id = #{domainId}
  AND device_model_id = #{deviceModelId}
